import torch
import pytest
from .AE.VAE import VAE  # Importing VAE class from the AE subdirectory

# New class to decode a given latent vector
class DecodeLatent:
    def __init__(self, model_path, latent_dim=48):
        self.model = VAE(latent_dim)
        self.model.load_state_dict(torch.load(model_path, map_location=torch.device('cpu')))
        self.model.eval()

    def decode(self, centroid):
        assert len(centroid) == self.model.latent_dim, "Centroid must be of length equal to latent_dim"
        centroid_tensor = torch.tensor(centroid, dtype=torch.float32).unsqueeze(0)  # Adding batch dimension
        decoded = self.model.decode(centroid_tensor)
        return decoded.squeeze(0)  # Removing batch dimension

